// // This module calculates the quotient and remainder of a 2-bit division operation.
// It ensures that the divisor is not zero to prevent division errors.
module divider_2bit (
    input [1:0] dividend,
    input [1:0] divisor,
    output reg [1:0] quotient,
    output reg [1:0] remainder
);

    always @(*) begin
        if (divisor == 0) begin
            quotient = 2'b00; // Undefined behavior, set to zero
            remainder = 2'b00; // Undefined behavior, set to zero
        end else begin
            quotient = dividend / divisor;
            remainder = dividend % divisor;
        end
    end
endmodule
